"use client";

import { type CSSProperties, type Ref } from "react";
import Picture from "./Picture";

type Jangsaeng = {
  id: string;
  kr: string;
  en: string;
  wish: string;
  wishEn: string;
};

/**
 * The ten 십장생 (sipjangsaeng) — ten things in nature believed not to age.
 * Painting them together is the deepest longevity wish a minhwa can make.
 * Listed in the canonical order, each with the wish it carries.
 */
const TEN: Jangsaeng[] = [
  { id: "sun", kr: "해", en: "sun", wish: "영원히 뜨는 빛", wishEn: "a light that never stops rising" },
  { id: "moon", kr: "달", en: "moon", wish: "이지러지지 않는 둥근 마음", wishEn: "a round heart that does not wane" },
  { id: "mountain", kr: "산", en: "mountain", wish: "흔들리지 않는 자리", wishEn: "a place that does not shake" },
  { id: "water", kr: "물", en: "water", wish: "마르지 않는 흐름", wishEn: "a current that does not run dry" },
  { id: "rock", kr: "돌", en: "rock", wish: "까이지 않는 단단함", wishEn: "a hardness that does not wear" },
  { id: "pine", kr: "소나무", en: "pine", wish: "늘 푸른 청춘", wishEn: "an evergreen youth" },
  { id: "herb", kr: "불로초", en: "herb of immortality", wish: "늙지 않는 약", wishEn: "the medicine against age" },
  { id: "crane", kr: "학", en: "crane", wish: "천 살을 사는 날개", wishEn: "a wing that lives a thousand years" },
  { id: "deer", kr: "사슴", en: "deer", wish: "선인의 짐승", wishEn: "the beast of the immortals" },
  { id: "turtle", kr: "거북", en: "turtle", wish: "만 살의 등껍질", wishEn: "a shell of ten thousand years" },
];

/**
 * Section 04 — 십장생, the ten longevity symbols. A scroll-scrubbed PINNED
 * sequence: the outer track is tall, the inner stage is sticky, and as the
 * visitor scrolls the ten symbols advance one position at a time. The
 * sun-moon-longevity painting is the fixed backdrop of the stage; the ten
 * symbols orbit across the foreground, each lighting up in turn.
 *
 * The active symbol, its scale, and the caption crossfade are derived purely
 * from the single `--minhwa-longevity` progress property that
 * useLongevityScrub writes on the stage — via calc()/clamp()/round() in
 * styles.css. transform and opacity only; no per-frame layout.
 *
 * Under reduced motion (or without JS) the section falls open: every symbol
 * is visible in a composed grid over the painting, and the useReveal hook
 * adds `is-visible` so nothing is stuck in a pre-state. The page is a
 * finished scroll either way.
 */
export default function LongevitySymbols({
  reduced,
  ref,
}: {
  reduced: boolean;
  ref?: Ref<HTMLElement>;
}) {
  // Each symbol's "slot" position in the orbit, advanced by --minhwa-longevity.
  // The active index is round(p * 9); styles.css owns the visual, the data
  // just needs the right --i and a stable key.
  return (
    <section
      className="minhwa-long"
      aria-labelledby="minhwa-long-title"
      data-minhwa-reduced={reduced || undefined}
      ref={ref}
    >
      <div className="minhwa-sechead minhwa-long__head" data-reveal>
        <span className="minhwa-sechead__no" lang="en" aria-hidden="true">
          04
        </span>
        <h2 className="minhwa-sechead__title" id="minhwa-long-title">
          십장생{" "}
          <span className="minhwa-sechead__en" lang="en">
            ten things that do not age
          </span>
        </h2>
      </div>

      {/* The pinned stage — sticky inside the tall track. The painting is
          the fixed ground; the ten symbols drift over it. */}
      <div className="minhwa-long__stage" data-reveal="panel">
        <div className="minhwa-long__backdrop">
          <Picture
            className="minhwa-long__art"
            stem="sun-moon-longevity"
            width={1024}
            height={768}
            alt="해와 달, 산과 물, 소나무와 학, 사슴과 거북 — 십장생 열 가지가 한 폭에 어우러진 민화. / Sun and moon, mountain and water, pine and crane, deer and turtle — the ten longevity symbols gathered in one minhwa."
          />
          <div className="minhwa-long__scrim" aria-hidden="true" />
        </div>

        {/* The ten symbols as an orbiting strip. Each carries its index so
            styles.css can light up the one round(p*9) selects. Under
            reduced motion the .minhwa-long--reduced ground (set on the
            section by [data-minhwa-reduced]) lays them out as a plain grid. */}
        <ol className="minhwa-long__orbit" aria-label="십장생 열 가지 / the ten longevity symbols">
          {TEN.map((s, i) => (
            <li
              key={s.id}
              className="minhwa-long__sym"
              style={{ "--i": `${i}` } as CSSProperties}
            >
              <span className="minhwa-long__sym-glyph" lang="ko">
                {s.kr}
              </span>
              <span className="minhwa-long__sym-en" lang="en">
                {s.en}
              </span>
            </li>
          ))}
        </ol>

        {/* The captions crossfade by the same progress: the active symbol's
            wish shows; the rest are present in the DOM for no-JS reading. */}
        <div className="minhwa-long__wishes">
          {TEN.map((s, i) => (
            <p
              key={s.id}
              className="minhwa-long__wish"
              style={{ "--i": `${i}` } as CSSProperties}
            >
              <span className="minhwa-long__wish-kr" lang="ko">
                {s.kr} — {s.wish}
              </span>
              <span className="minhwa-long__wish-en" lang="en">
                {s.en} — {s.wishEn}
              </span>
            </p>
          ))}
        </div>

        {/* Progress rail — a reading-aid that fills with --minhwa-longevity.
            Decorative; the legend above carries the meaning accessibly. */}
        <div
          className="minhwa-long__rail"
          aria-hidden="true"
          data-reveal="panel"
        >
          <span className="minhwa-long__rail-fill" />
          <span className="minhwa-long__rail-label" lang="ko">
            스크롤하면 열 가지가 차례로 {" "}
            <span lang="en">scroll to walk the ten</span>
          </span>
        </div>
      </div>
    </section>
  );
}

"use client";

import type { CSSProperties } from "react";

type NarrationProps = {
  /** The full, real string — exposed to AT and find-in-page exactly once. */
  text: string;
  /** BCP-47 language tag for the string (sets the lang on both spans). */
  lang?: string;
  className?: string;
  /** ms between glyphs — the curator's reading pace. */
  step?: number;
  /** ms before the first glyph. */
  start?: number;
};

/**
 * Accessible split text for the gallery's narration lines — the symbolic
 * meaning of each motif, read aloud by an imagined curator.
 *
 * The real string lives in a visually-hidden span (screen readers and
 * find-in-page get it whole, once); the animated copy is aria-hidden, one
 * span per glyph, each carrying its own transition-delay as a custom
 * property. The glyphs' pre-reveal state is gated behind the `.minhwa-js`
 * root class and the panel's `is-visible` class — so without JavaScript, or
 * under reduced motion, the line is simply there, whole.
 *
 * Split with Array.from so Hangul syllables and jamo clusters survive as
 * single code points; spaces become no-break spaces so a glyph never
 * collapses at a line edge.
 */
export default function Narration({
  text,
  lang,
  className,
  step = 42,
  start = 0,
}: NarrationProps) {
  const glyphs = Array.from(text);
  return (
    <span className={`minhwa-narration ${className ?? ""}`} lang={lang}>
      <span className="minhwa-sr">{text}</span>
      <span aria-hidden="true" className="minhwa-narration__row">
        {glyphs.map((g, i) => (
          <span
            key={i}
            className="minhwa-narration__g"
            style={{ "--pn": `${start + i * step}ms` } as CSSProperties}
          >
            {g === " " ? "\u00A0" : g}
          </span>
        ))}
      </span>
    </span>
  );
}

"use client";

import { useEffect, useRef, useState } from "react";
import type { CSSProperties } from "react";

type ObangColor = {
  id: string;
  /** swatch + accent-live value — must match a token in styles.css */
  value: string;
  /** deep variant for the focus ring / functional accent when this color is active */
  deep: string;
  hanja: string;
  name: string;
  en: string;
  direction: string;
  directionEn: string;
  element: string;
  motif: string;
  motifEn: string;
  meaning: string;
  meaningEn: string;
};

const COLORS: ObangColor[] = [
  {
    id: "cheong",
    value: "#2f6e6a",
    deep: "#235653",
    hanja: "靑",
    name: "청",
    en: "blue-green",
    direction: "동",
    directionEn: "East",
    element: "목 木 · 봄",
    motif: "소나무, 호랑이의 하늘",
    motifEn: "the pine, the tiger's sky",
    meaning:
      "해가 처음 닿는 동쪽의 빛. 민화에서 청은 늘 푸른 소나무와, 호랑이가 앉은 밤하늘에 깔린다. 오래 사는 기운이다.",
    meaningEn:
      "The light of the east, where the sun first touches. In minhwa, cheong lays under the evergreen pine and the night sky the tiger sits beneath — the breath of long life.",
  },
  {
    id: "jeok",
    value: "#c8362b",
    deep: "#7a241c",
    hanja: "赤",
    name: "적",
    en: "red",
    direction: "남",
    directionEn: "South",
    element: "화 火 · 여름",
    motif: "호랑이 털, 붉은 인장",
    motifEn: "the tiger's coat, the red seal",
    meaning:
      "삿된 것을 물리치는 붉은 빛. 호랑이의 털과 화가가 마지막에 찍는 인장이 모두 이 빛이다. 민화에서 적은 보호와 마침의 색이다.",
    meaningEn:
      "The red that wards off ill. The tiger's coat and the seal a painter stamps last both carry this light — in minhwa, jeok is the color of protection and of finishing.",
  },
  {
    id: "hwang",
    value: "#d99a1f",
    deep: "#9c6a12",
    hanja: "黃",
    name: "황",
    en: "yellow",
    direction: "중앙",
    directionEn: "Center",
    element: "토 土 · 환절",
    motif: "해, 십장생의 금빛",
    motifEn: "the sun, the gold of the ten longevity symbols",
    meaning:
      "다섯 방위가 모이는 한가운데, 임금의 빛. 민화에서 황은 해와, 오래오래 사는 열 가지 상징의 금빛으로 나타난다. 정확히 쓰는 색이다.",
    meaningEn:
      "The center where the five directions meet — the sovereign light. In minhwa, hwang appears as the sun and as the gold of the ten longevity symbols. It is spent exactly, not freely.",
  },
  {
    id: "baek",
    value: "#fbf8ef",
    deep: "#5a4a3c",
    hanja: "白",
    name: "백",
    en: "white",
    direction: "서",
    directionEn: "West",
    element: "금 金 · 가을",
    motif: "달, 여백, 호분",
    motifEn: "the moon, the empty ground, the powdered shell",
    meaning:
      "결백과 비움의 빛. 민화에서 백은 종이 자체이자, 색과 색 사이의 호분 숨이고, 해의 짝인 달이다. 그림의 여백은 빈 것이 아니라 채워진 것이다.",
    meaningEn:
      "The light of clarity and of emptying. In minhwa, baek is the paper itself — the powdered-shell breath between colors, and the moon paired with the sun. The empty ground of a painting is not vacant; it is full.",
  },
  {
    id: "heuk",
    value: "#1a1410",
    deep: "#1a1410",
    hanja: "黑",
    name: "흑",
    en: "black",
    direction: "북",
    directionEn: "North",
    element: "수 水 · 겨울",
    motif: "윤곽선, 까치, 먹물",
    motifEn: "the outline, the magpie, the ink",
    meaning:
      "모든 색이 돌아가 쉬는 어둠. 민화의 검은 윤곽선은 채색이 끝난 뒤 그어, 다섯 빛을 제자리에 앉힌다. 까치도 이 빛으로 기쁜 소식을 가져온다.",
    meaningEn:
      "The dark every color returns to for rest. The black outline of a minhwa is drawn after the coloring, to seat all five lights in their places — and the magpie, too, brings the glad tidings in this light.",
  },
];

/**
 * Section 03 — 오방색 navigator. The five directional colors as a *system*,
 * not decoration: pick one and it becomes the gallery's living accent
 * (--minhwa-accent-live on .minhwa-root), tinting the focus ring, the
 * hover washes, and the section rule. Each color also names the minhwa
 * motif it lives in — so the palette is taught as the cosmology behind the
 * paintings, not as swatches.
 *
 * Every note is in the DOM and visible without JavaScript — with JS, only
 * the active note shows. Color swaps are instant by design: pigment does
 * not ease. baek would vanish as an accent on hanji paper, so when 백 is
 * selected the accent borrows ink-soft (a soft earth tone) instead.
 */
export default function ObangsaekNavigator() {
  const sectionRef = useRef<HTMLElement | null>(null);
  const [active, setActive] = useState("jeok");

  useEffect(() => {
    const root = sectionRef.current?.closest<HTMLElement>(".minhwa-root");
    if (!root) return;
    const color = COLORS.find((c) => c.id === active);
    if (!color) return;
    // baek would vanish as an accent on hanji; borrow ink-soft instead.
    const value = color.id === "baek" ? color.deep : color.value;
    root.style.setProperty("--minhwa-accent-live", value);
    return () => {
      root.style.removeProperty("--minhwa-accent-live");
    };
  }, [active]);

  return (
    <section
      className="minhwa-obang"
      aria-labelledby="minhwa-obang-title"
      ref={sectionRef}
    >
      <div className="minhwa-sechead" data-reveal>
        <span className="minhwa-sechead__no" lang="en" aria-hidden="true">
          03
        </span>
        <h2 className="minhwa-sechead__title" id="minhwa-obang-title">
          오방색{" "}
          <span className="minhwa-sechead__en" lang="en">
            the five colors, walked
          </span>
        </h2>
      </div>

      <p className="minhwa-obang__intro" data-reveal>
        다섯 방위, 다섯 빛. 민화의 색은 취향이 아니라 우주관이다 — 동·남·중앙·서·북,
        각 빛이 품은 상징이 그림 전체를 짓는다. 한 빛을 고르면 화랑이 그 빛으로
        숨을 쉰다.
      </p>
      <p className="minhwa-obang__intro-en" lang="en" data-reveal>
        Five directions, five lights. In minhwa the palette is a cosmology, not
        a taste — east, south, center, west, north, and the symbol each light
        holds builds the whole painting. Choose one and the gallery breathes
        in that hue.
      </p>

      <ul className="minhwa-obang__rail" data-reveal>
        {COLORS.map((c) => {
          const isActive = active === c.id;
          return (
            <li key={c.id} className="minhwa-obang__cell">
              <button
                type="button"
                className="minhwa-obang__btn"
                style={
                  {
                    "--minhwa-swatch": c.value,
                    "--minhwa-swatch-deep": c.deep,
                  } as CSSProperties
                }
                data-active={isActive || undefined}
                data-baek={c.id === "baek" || undefined}
                aria-pressed={isActive}
                aria-controls={`minhwa-obang-note-${c.id}`}
                onClick={() => setActive(c.id)}
                onMouseEnter={() => setActive(c.id)}
                onFocus={() => setActive(c.id)}
              >
                <span className="minhwa-obang__swatch" aria-hidden="true" />
                <span className="minhwa-obang__hanja">{c.hanja}</span>
                <span className="minhwa-obang__name">
                  {c.name}{" "}
                  <span className="minhwa-obang__name-en" lang="en">
                    {c.en}
                  </span>
                </span>
                <span className="minhwa-obang__dir">
                  {c.direction} · <span lang="en">{c.directionEn}</span> ·{" "}
                  {c.element}
                </span>
              </button>
            </li>
          );
        })}
      </ul>

      <div className="minhwa-obang__notes" data-reveal>
        {COLORS.map((c) => {
          const isActive = active === c.id;
          return (
            <article
              key={c.id}
              id={`minhwa-obang-note-${c.id}`}
              className={`minhwa-obang__note ${
                isActive ? "is-open" : "is-closed"
              }`}
              aria-label={`${c.name} — ${c.motif}`}
            >
              <h3 className="minhwa-obang__note-head">
                {c.hanja} {c.name} · {c.direction}
                <span className="minhwa-obang__note-en" lang="en">
                  {" "}
                  — {c.directionEn}
                </span>
              </h3>
              <p className="minhwa-obang__note-motif">
                이 빛이 사는 자리: {c.motif}
              </p>
              <p className="minhwa-obang__note-meaning">{c.meaning}</p>
              <p className="minhwa-obang__note-en" lang="en">
                {c.meaningEn}
              </p>
            </article>
          );
        })}
      </div>
    </section>
  );
}

"use client";

type PictureProps = {
  /** filename stem under /media/minhwa/, e.g. "hero-tiger-magpie". */
  stem: string;
  alt: string;
  /** optional explicit width/height to reserve the box and avoid CLS. */
  width?: number;
  height?: number;
  className?: string;
  loading?: "eager" | "lazy";
  /** Optional decoding hint — default "async" for off-screen panels. */
  decoding?: "async" | "sync" | "auto";
};

/**
 * The one way a minhwa illustration enters the page: an AVIF <source> with a
 * WebP fallback on a <picture>, with a real bilingual alt and reserved box
 * dimensions so the panel never causes layout shift. eager + fetchpriority
 * only for the hero (the first paint); every later panel is lazy and async.
 *
 * The src never carries a query string and never references a derivative —
 * capture-pipeline outputs (poster-*, og.png, loop.webm) are produced
 * elsewhere and are excluded from the budget by check-budget.
 *
 * The minhwa illustrations carry NO text by design — every Hangul caption,
 * symbol meaning, and seal is real HTML/SVG/CSS on top, so Hangul stays
 * crisp vector and fully accessible.
 */
export default function Picture({
  stem,
  alt,
  width,
  height,
  className,
  loading = "lazy",
  decoding = "async",
}: PictureProps) {
  return (
    <picture
      className={className ? `minhwa-picture ${className}` : "minhwa-picture"}
    >
      <source srcSet={`/media/minhwa/${stem}.avif`} type="image/avif" />
      <source srcSet={`/media/minhwa/${stem}.webp`} type="image/webp" />
      <img
        className="minhwa-picture__img"
        src={`/media/minhwa/${stem}.webp`}
        alt={alt}
        width={width}
        height={height}
        loading={loading}
        decoding={decoding}
      />
    </picture>
  );
}

"use client";

type SealMarkProps = {
  className?: string;
  /**
   * The square seal's reading. Default is "民畵" (min·hwa) in a 2×2 세로쓰기
   * arrangement — right column first (民), left column second (畵), the way
   * a real Korean/Chinese seal is read.
   */
  chars?: [string, string] | [string, string, string, string];
  /** vermillion fill — defaults to the seal-red token via CSS. */
  fill?: string;
};

/**
 * A vermillion 인장 (seal stamp), drawn as crisp SVG so the Hangul stays
 * vector at any scale. The mark a minhwa painter presses onto a finished
 * work — "this one is done, this one is mine."
 *
 * Two layouts:
 *   2 chars  — a single column, one glyph stacked on the next.
 *   4 chars  — the classic 2×2 grid, read top-to-bottom in the right column
 *              then top-to-bottom in the left column (세로쓰기 / 右起).
 *
 * The fill defaults to the `--seal-red` token set in styles.css; passing a
 * literal fill is allowed for the obangsaek-tinted variant. The seal's
 * hammered rim (a slightly inset, uneven rect) is the one detail that stops
 * it reading as a flat red square — it is ink pressed into paper.
 */
export default function SealMark({
  className,
  chars = ["民", "畵"],
  fill,
}: SealMarkProps) {
  const isQuad = chars.length === 4;
  return (
    <svg
      className={`minhwa-sealmark ${className ?? ""}`}
      viewBox="0 0 120 120"
      role="img"
      aria-hidden="true"
      focusable="false"
    >
      {/* the stamp body — slightly rounded, with an inset double rim */}
      <rect
        x="3"
        y="3"
        width="114"
        height="114"
        rx="7"
        fill={fill ?? "var(--seal-red, #b6241b)"}
      />
      {/* inner rim — the hammered edge of a real carved seal */}
      <rect
        x="9"
        y="9"
        width="102"
        height="102"
        rx="4"
        fill="none"
        stroke="var(--baek, #fbf8ef)"
        strokeWidth="2.4"
        opacity="0.92"
      />
      {/* the glyphs — white (호분) carved-out characters, the way an actual
          seal prints: the field is red, the letters are the paper showing
          through the carved strokes. */}
      <g
        fill="var(--baek, #fbf8ef)"
        fontFamily="var(--font-display), 'Gaegu',cursive"
        textAnchor="middle"
        fontWeight={700}
      >
        {isQuad ? (
          <>
            {/* right column (read first): chars[0] top, chars[1] bottom */}
            <text x="74" y="54" fontSize="40">
              {chars[0]}
            </text>
            <text x="74" y="100" fontSize="40">
              {chars[1]}
            </text>
            {/* left column (read second): chars[2] top, chars[3] bottom */}
            <text x="40" y="54" fontSize="40">
              {chars[2]}
            </text>
            <text x="40" y="100" fontSize="40">
              {chars[3]}
            </text>
          </>
        ) : (
          <>
            {/* single column: chars[0] top, chars[1] bottom */}
            <text x="60" y="56" fontSize="44">
              {chars[0]}
            </text>
            <text x="60" y="102" fontSize="44">
              {chars[1]}
            </text>
          </>
        )}
      </g>
    </svg>
  );
}

"use client";

import { useEffect, type RefObject } from "react";

/**
 * Drives the 십장생 (ten longevity symbols) section — a scroll-scrubbed
 * PINNED sequence. The section is a tall outer track; inside it a sticky
 * stage stays fixed while the visitor scrolls, and the ten symbols advance
 * one position at a time.
 *
 * The hook reads the section's scroll progress (0 at the top of the track,
 * 1 at the bottom) once per rAF and writes it as a single CSS custom
 * property on the sticky element:
 *
 *   --minhwa-longevity  ∈ [0, 1]
 *
 * styles.css derives the active symbol, the caption crossfade, and the
 * scale of the current symbol purely from that property via calc()/clamp()/
 * round() — no per-frame layout, no React state round-trip. transform and
 * opacity only.
 *
 * The hook clamps dt to 48ms so a backgrounded tab can't lurch on return,
 * pauses entirely on `visibilitychange` (hidden), and never runs under
 * reduced motion — under reduced motion the section simply shows all ten
 * symbols in a composed grid (styles.css pins --minhwa-longevity at a state
 * where every symbol is visible), which `useReveal` handles via the
 * `is-visible` class.
 *
 * `sectionRef` should be the OUTER track element (the tall one). The sticky
 * child is found by class `.minhwa-long__stage`.
 */
export function useLongevityScrub(
  sectionRef: RefObject<HTMLElement | null>,
  disabled: boolean,
) {
  useEffect(() => {
    if (disabled) return;
    const section = sectionRef.current;
    if (!section) return;
    const stage = section.querySelector<HTMLElement>(".minhwa-long__stage");
    if (!stage) return;

    let raf = 0;
    let running = false;

    const compute = () => {
      const rect = section.getBoundingClientRect();
      const viewH = window.innerHeight;
      // The track is taller than the viewport (track = stage height + the
      // scroll distance). Progress is how far the track top has risen above
      // the viewport top, over the scrollable distance.
      const scrollable = Math.max(rect.height - viewH, 1);
      const traveled = Math.min(Math.max(-rect.top / scrollable, 0), 1);
      stage.style.setProperty("--minhwa-longevity", traveled.toFixed(4));
    };

    const wake = () => {
      if (running) return;
      running = true;
      raf = window.requestAnimationFrame(() => {
        running = false;
        compute();
      });
    };

    const onVisibility = () => {
      if (document.hidden) {
        if (raf) window.cancelAnimationFrame(raf);
        running = false;
      } else {
        wake();
      }
    };

    compute();
    window.addEventListener("scroll", wake, { passive: true });
    window.addEventListener("resize", wake, { passive: true });
    document.addEventListener("visibilitychange", onVisibility);

    return () => {
      if (raf) window.cancelAnimationFrame(raf);
      window.removeEventListener("scroll", wake);
      window.removeEventListener("resize", wake);
      document.removeEventListener("visibilitychange", onVisibility);
      stage.style.removeProperty("--minhwa-longevity");
    };
  }, [sectionRef, disabled]);
}

"use client";

import { useSyncExternalStore } from "react";

const QUERY = "(prefers-reduced-motion: reduce)";

function subscribe(onChange: () => void): () => void {
  const mql = window.matchMedia(QUERY);
  mql.addEventListener("change", onChange);
  return () => mql.removeEventListener("change", onChange);
}

function getSnapshot(): boolean {
  return window.matchMedia(QUERY).matches;
}

function getServerSnapshot(): boolean {
  return false;
}

/**
 * True when the OS asks for reduced motion.
 * SSR-safe: the server snapshot is `false`; on the client the real value is
 * read synchronously, and live changes to the setting re-render immediately.
 */
export function usePrefersReducedMotion(): boolean {
  return useSyncExternalStore(subscribe, getSnapshot, getServerSnapshot);
}

"use client";

import { useEffect, useRef } from "react";

/**
 * Reveals descendants marked with [data-reveal] as they enter the viewport,
 * by adding an `is-visible` class. The pre-reveal state lives in styles.css
 * and is gated behind the `.minhwa-js` root class — so with JavaScript off,
 * every word and every minhwa is plainly visible. The page is a finished
 * gallery either way.
 *
 * Three flavors, mirroring the gallery's three kinds of beat:
 *   data-reveal                  — the element itself rises and settles
 *                                  (820ms ease-settle), with an 80ms stagger
 *                                  between elements of the same observer
 *                                  batch, so a screenful never moves as one.
 *   data-reveal="stamp"          — a motif that lands with a spring-press
 *                                  pop (minhwa is cheerful, not austere):
 *                                  opacity + scale 0.82→1 + a tiny rise. The
 *                                  class is added the same way; styles.css
 *                                  owns the curve.
 *   data-reveal="panel"          — a panel container; it does not animate
 *                                  itself, it only receives `is-visible` so
 *                                  its children (a stamp, a narration, a seal
 *                                  gate) can begin their own delays.
 */
export function useReveal<T extends HTMLElement>(disabled: boolean) {
  const rootRef = useRef<T | null>(null);

  useEffect(() => {
    const root = rootRef.current;
    if (!root) return;
    const targets = Array.from(
      root.querySelectorAll<HTMLElement>("[data-reveal]"),
    );

    if (disabled || !("IntersectionObserver" in window)) {
      for (const el of targets) el.classList.add("is-visible");
      return;
    }

    const io = new IntersectionObserver(
      (hits) => {
        let batch = 0;
        for (const hit of hits) {
          if (!hit.isIntersecting) continue;
          const el = hit.target as HTMLElement;
          if (el.dataset.reveal !== "panel") {
            el.style.transitionDelay = `${batch * 80}ms`;
            batch += 1;
          }
          el.classList.add("is-visible");
          io.unobserve(el);
        }
      },
      { threshold: 0.18, rootMargin: "0px 0px -8% 0px" },
    );
    for (const el of targets) io.observe(el);
    return () => io.disconnect();
  }, [disabled]);

  return rootRef;
}

"use client";

import { useCallback, useEffect, useRef, useState } from "react";

/**
 * Drives the 인장 (seal-stamp) confirmation mechanic.
 *
 * A minhwa painter signs a finished work with a red vermillion seal — the
 * mark that says "this one is mine, this one is done." Here the seal is a UI
 * pattern: the visitor presses (or focuses, or the seal self-stamps when its
 * panel enters view on touch/reduced-motion), and a vermillion 도장 presses
 * down onto the section with a deliberate even ease — land, settle, and a
 * 1px ink rim that expands to certify the mark.
 *
 * State machine:
 *   idle      → sealed? false — the seal hangs ready, dimmed.
 *   stamping  → sealed? true  — CSS animates the descend + rim via the
 *                `is-stamped` class (a one-shot, not a loop).
 *
 * `auto` (default true): on coarse pointers OR reduced motion the seal
 * self-stamps the first time its panel enters the viewport, so touch users
 * and reduced-motion visitors never miss the certification — and the page is
 * fully composed without a tap. On fine pointers without reduced motion the
 * seal waits for the visitor's press/focus, because pressing a seal is the
 * point.
 *
 * Returns the ref to attach to the seal's container, the `stamped` flag, and
 * a `stamp()` callback (used by the button's onClick and onKeyDown). The ref
 * is also what the IntersectionObserver watches for auto-stamp.
 */
export function useSealStamp<T extends HTMLElement>(opts?: {
  auto?: boolean;
  disabled?: boolean;
}) {
  const auto = opts?.auto ?? true;
  const disabled = opts?.disabled ?? false;

  const ref = useRef<T | null>(null);
  // Under reduced motion the seal should land instantly on first reveal —
  // the visitor sees a composed, already-certified page. `disabled` is fixed
  // for the component's life, so it seeds the initial state directly.
  const [stamped, setStamped] = useState(disabled);

  const stamp = useCallback(() => setStamped(true), []);

  // Self-stamp on coarse pointer / reduced motion, the first time the seal
  // enters the viewport. Fine-pointer + full-motion visitors press it.
  useEffect(() => {
    if (!auto || disabled) return;
    const fine = window.matchMedia("(pointer: fine)").matches;
    if (fine && !disabled) return; // wait for the press
    const el = ref.current;
    if (!el || !("IntersectionObserver" in window)) {
      setStamped(true);
      return;
    }
    const io = new IntersectionObserver(
      (hits) => {
        for (const h of hits) {
          if (h.isIntersecting) {
            setStamped(true);
            io.disconnect();
            break;
          }
        }
      },
      { threshold: 0.5 },
    );
    io.observe(el);
    return () => io.disconnect();
  }, [auto, disabled]);

  return { ref, stamped, stamp };
}

"use client";

import { useEffect, useRef } from "react";
import "./styles.css";
import { gaegu, notoSerifKR, fraunces } from "./fonts";
import Hero from "./components/Hero";
import PeonyProsperity from "./components/PeonyProsperity";
import ObangsaekNavigator from "./components/ObangsaekNavigator";
import LongevitySymbols from "./components/LongevitySymbols";
import FolkFooter from "./components/FolkFooter";
import { usePrefersReducedMotion } from "./hooks/usePrefersReducedMotion";
import { useReveal } from "./hooks/useReveal";
import { useLongevityScrub } from "./hooks/useLongevityScrub";

/**
 * MINHWA — 민화 / A Gallery of Wishes.
 *
 * A joyful folk-painting gallery where every motif is a wish: 호랑이와 까치
 * (good news + protection), 모란 (prosperity), 십장생 (long life) under 해와
 * 달. Aged hanji ground, ink-black line work, and the obangsaek five-color
 * system as the cosmology behind every painting — not decoration. Minhwa is
 * the bright opposite of austere ink: naive, vivid, generous, full of
 * meaning. The illustrations are generated (ComfyUI; recipe in
 * image-recipe.md) and carry no text — every Hangul caption, symbol meaning,
 * and seal is real HTML/SVG/CSS.
 *
 * `.minhwa-js` is added imperatively on mount (it never changes — a signal
 * to CSS that JS is alive, not React state): every pre-reveal style is
 * gated behind it, and with JavaScript off the full gallery simply stands
 * finished — every minhwa, every meaning, every seal visible. The reveal
 * observer and the longevity scrub both attach to the same root; under
 * reduced motion the scrub never runs and the longevity section opens as a
 * composed grid.
 *
 * The page is Korean-first: every pairing leads with Hangul, English is the
 * leaning subtitle. Gaegu (a naive hand-brushed face) is the display voice
 * — Black Han Sans would shout; Gaegu smiles, which is what a minhwa does.
 */
export default function MinhwaPage() {
  const rootRef = useRef<HTMLDivElement | null>(null);
  const reduced = usePrefersReducedMotion();
  const revealRef = useReveal<HTMLDivElement>(reduced);
  const longRef = useRef<HTMLElement | null>(null);

  // One callback ref merges the page-root refs (the reveal observer watches
  // [data-reveal] descendants inside the same root). The longevity section
  // ref is separate — useLongevityScrub watches its own outer track.
  const setRootNode = (node: HTMLDivElement | null) => {
    rootRef.current = node;
    revealRef.current = node;
  };

  useEffect(() => {
    const el = rootRef.current;
    if (!el) return;
    el.classList.add("minhwa-js");
    window.parent?.postMessage({ type: "oneshot:ready", slug: "minhwa" }, "*");
  }, []);

  useLongevityScrub(longRef, reduced);

  return (
    <div
      id="minhwa-top"
      ref={setRootNode}
      className={`${gaegu.variable} ${notoSerifKR.variable} ${fraunces.variable} minhwa-root`}
    >
      <Hero />
      <main>
        <PeonyProsperity />
        <ObangsaekNavigator />
        <LongevitySymbols reduced={reduced} ref={longRef} />
      </main>
      <FolkFooter />

      {/* Hanji grain: one static feTurbulence pass over the whole sheet.
          Warm aged fibers, never animated — the page is a sheet of paper,
          not a screen. Decorative; pointer-transparent. */}
      <div className="minhwa-grain" aria-hidden="true">
        <svg width="100%" height="100%" preserveAspectRatio="none">
          <filter id="minhwa-grain-f" x="0" y="0" width="100%" height="100%">
            <feTurbulence
              type="fractalNoise"
              baseFrequency="0.7"
              numOctaves="2"
              seed="11"
              stitchTiles="stitch"
            />
            <feColorMatrix
              type="matrix"
              values="0 0 0 0 0.10  0 0 0 0 0.08  0 0 0 0 0.06  0 0 0 0.065 0"
            />
          </filter>
          <rect width="100%" height="100%" filter="url(#minhwa-grain-f)" />
        </svg>
      </div>
    </div>
  );
}

/* =========================================================================
   MINHWA — 민화 / A Gallery of Wishes
   Korean folk-painting gallery. Aged hanji ground, ink-black line work, the
   obangsaek five-color system as cosmology. Joyful, generous, symbolic — the
   bright opposite of austere ink. All tokens live here; everything is scoped
   under .minhwa-root.
   ========================================================================= */

.minhwa-root {
  /* ---- palette (every rendered color a named token) ---- */
  --hanji: #f5efe1;
  --hanji-deep: #ece3cf;
  --heuk: #1a1410;
  --ink-soft: #5a4a3c;
  --jeok: #c8362b;
  --cheong: #2f6e6a;
  --hwang: #d99a1f;
  --baek: #fbf8ef;
  --jeongjo: #7a241c;
  --seal-red: #b6241b;

  /* the living accent — defaults to 적 (the gallery's signature red); the
     obangsaek navigator overrides it per-section. Used for the focus ring,
     the section rule, and hover washes so pigment is felt page-wide. */
  --minhwa-accent-live: var(--jeok);
  --minhwa-accent-deep: var(--jeongjo);

  /* ---- typography stacks (Korean face always leads) ---- */
  --font-display: var(--font-display), "Gaegu", "Noto Serif KR", cursive;
  --font-kr: var(--font-kr), "Noto Serif KR", "Pretendard", serif;
  --font-en: var(--font-en), "Fraunces", Georgia, serif;

  /* ---- motion vocabulary ---- */
  --ease-stamp: cubic-bezier(0.34, 1.56, 0.64, 1);
  --ease-settle: cubic-bezier(0.16, 1, 0.3, 1);
  --ease-press: cubic-bezier(0.5, 0, 0.2, 1);

  /* the longevity scrub progress; set by useLongevityScrub on the stage.
     unset (no-JS) and reduced-motion both read as "all visible". */
  --minhwa-longevity: 0;

  background: var(--hanji);
  color: var(--heuk);
  font-family: var(--font-kr);
  font-size: clamp(16.5px, 0.85vw + 12px, 18.5px);
  line-height: 1.78;
  -webkit-font-smoothing: antialiased;
  text-rendering: optimizeLegibility;
  position: relative;
  overflow-x: clip;
  isolation: isolate;
}

/* Korean tracking opens a hair so syllables breathe; English leans italic. */
.minhwa-root :lang(ko) {
  letter-spacing: 0.005em;
}
.minhwa-root :lang(en) {
  font-family: var(--font-en);
  font-style: italic;
}

/* Custom selection — vermillion ground, hanji text. */
.minhwa-root ::selection {
  background: var(--minhwa-accent-deep);
  color: var(--baek);
}
.minhwa-root ::-moz-selection {
  background: var(--minhwa-accent-deep);
  color: var(--baek);
}

/* Visually-hidden real string for split text (screen readers + find-in-page). */
.minhwa-sr {
  position: absolute !important;
  width: 1px;
  height: 1px;
  padding: 0;
  margin: -1px;
  overflow: hidden;
  clip: rect(0, 0, 0, 0);
  white-space: nowrap;
  border: 0;
}

/* Art-directed focus — the living accent, double-weight for a folk weight. */
.minhwa-root :focus-visible {
  outline: none;
  box-shadow: 0 0 0 2px var(--hanji), 0 0 0 4px var(--minhwa-accent-live);
  border-radius: 3px;
}

/* The hanji grain — one static full-viewport feTurbulence pass, multiplied.
   Warm aged fibers, never animated. Pointer-transparent. */
.minhwa-grain {
  position: fixed;
  inset: 0;
  z-index: 1;
  pointer-events: none;
  mix-blend-mode: multiply;
  opacity: 0.55;
}
/* a faint foxing vignette layered with the grain */
.minhwa-root::before {
  content: "";
  position: fixed;
  inset: 0;
  z-index: 0;
  pointer-events: none;
  background: radial-gradient(
    120% 100% at 50% 40%,
    transparent 55%,
    rgba(122, 36, 28, 0.04) 100%
  );
}
.minhwa-root > * {
  position: relative;
  z-index: 2;
}

/* ============================ layout primitives ========================= */

.minhwa-root * {
  box-sizing: border-box;
}

.minhwa-hero,
.minhwa-peony,
.minhwa-obang,
.minhwa-long,
.minhwa-foot {
  max-width: 100%;
}

.minhwa-peony,
.minhwa-obang,
.minhwa-foot {
  padding: clamp(72px, 12vh, 140px) clamp(20px, 5vw, 64px);
}

.minhwa-sechead {
  display: flex;
  align-items: baseline;
  gap: clamp(14px, 2.4vw, 26px);
  max-width: 1120px;
  margin: 0 auto clamp(28px, 5vh, 48px);
}
.minhwa-sechead__no {
  font-family: var(--font-en);
  font-style: normal;
  font-weight: 600;
  font-size: clamp(1rem, 1.4vw, 1.25rem);
  color: var(--minhwa-accent-deep);
  letter-spacing: 0.08em;
  border-bottom: 2px solid var(--minhwa-accent-live);
  padding-bottom: 4px;
}
.minhwa-sechead__title {
  font-family: var(--font-display);
  font-weight: 700;
  font-size: clamp(2.1rem, 5.6vw, 3.6rem);
  line-height: 1.12;
  margin: 0;
  color: var(--heuk);
}
.minhwa-sechead__en {
  display: block;
  font-family: var(--font-en);
  font-weight: 500;
  font-style: italic;
  font-size: 0.42em;
  color: var(--ink-soft);
  margin-top: 0.35em;
  letter-spacing: 0.01em;
}

/* ============================ reveal gating ============================= */
/* Pre-reveal states are GATED behind .minhwa-js — without JS the whole
   gallery is plainly visible. Every reveal is transform/opacity only. */
.minhwa-js [data-reveal]:not(.is-visible) {
  opacity: 0;
  transform: translateY(18px);
  transition: opacity 820ms var(--ease-settle), transform 820ms var(--ease-settle);
}
.minhwa-js [data-reveal]:not(.is-visible) {
  /* transition-delay is set inline per-batch by useReveal */
}
.minhwa-js [data-reveal].is-visible,
.minhwa-js [data-reveal] {
  transition: opacity 820ms var(--ease-settle), transform 820ms var(--ease-settle);
}
.minhwa-js [data-reveal].is-visible {
  opacity: 1;
  transform: none;
}

/* stamp flavor — a motif that lands with a spring pop */
.minhwa-js [data-reveal="stamp"]:not(.is-visible) {
  opacity: 0;
  transform: translateY(18px) scale(0.82);
  transition: opacity 760ms var(--ease-stamp), transform 760ms var(--ease-stamp);
}
.minhwa-js [data-reveal="stamp"].is-visible {
  opacity: 1;
  transform: none;
}

/* panel flavor — itself static; only its children animate on .is-visible */
.minhwa-js [data-reveal="panel"]:not(.is-visible) {
  opacity: 1; /* the panel is a container; keep it visible, children gate themselves */
  transform: none;
}

/* ============================ HERO ============================ */

.minhwa-hero {
  min-height: 100svh;
  display: grid;
  grid-template-columns: minmax(0, 1fr) minmax(0, 1fr);
  grid-template-areas:
    "mount text"
    "mount text";
  gap: clamp(24px, 4vw, 56px);
  align-items: center;
  padding: clamp(28px, 5vw, 56px) clamp(20px, 5vw, 64px) clamp(56px, 9vh, 96px);
  max-width: 1320px;
  margin: 0 auto;
}
.minhwa-hero__mount {
  grid-area: mount;
  position: relative;
  display: flex;
  justify-content: center;
}
.minhwa-picture {
  display: block;
  line-height: 0;
}
.minhwa-hero__art {
  display: block;
  width: auto;
  height: clamp(420px, 78vh, 760px);
  max-width: 100%;
  border: 1px solid rgba(26, 20, 16, 0.18);
  box-shadow: 0 24px 60px rgba(26, 20, 16, 0.18);
  background: var(--hanji-deep);
  object-fit: contain;
}
.minhwa-picture__img {
  display: block;
  width: 100%;
  height: 100%;
  object-fit: cover;
}
.minhwa-hero__art .minhwa-picture__img {
  object-fit: contain;
}

/* obangsaek sun + moon floating accents — 황 + 청. Decorative, aria-hidden. */
.minhwa-hero__sun,
.minhwa-hero__moon {
  position: absolute;
  display: block;
  pointer-events: none;
}
.minhwa-hero__sun {
  top: 4%;
  right: -3%;
  width: clamp(54px, 7vw, 92px);
  height: clamp(54px, 7vw, 92px);
  animation: minhwa-sun-drift 7.1s var(--ease-settle) infinite alternate;
}
.minhwa-hero__moon {
  bottom: 8%;
  left: -4%;
  width: clamp(40px, 5vw, 64px);
  height: clamp(40px, 5vw, 64px);
  animation: minhwa-moon-drift 6.3s var(--ease-settle) infinite alternate;
}
.minhwa-hero__disc {
  display: block;
  width: 100%;
  height: 100%;
  border-radius: 50%;
  background: radial-gradient(circle at 38% 35%, #efb43a 0%, var(--hwang) 62%, #b67b13 100%);
  box-shadow: 0 0 0 6px rgba(217, 154, 31, 0.16);
}
.minhwa-hero__disc--moon {
  background: radial-gradient(circle at 40% 38%, var(--baek) 0%, #e9e3ce 70%, #b9b095 100%);
  box-shadow: 0 0 0 6px rgba(47, 110, 106, 0.18);
}
@keyframes minhwa-sun-drift {
  from {
    transform: translate(0, 0);
  }
  to {
    transform: translate(-8px, 12px);
  }
}
@keyframes minhwa-moon-drift {
  from {
    transform: translate(0, 0);
  }
  to {
    transform: translate(10px, -10px);
  }
}

/* hero text block */
.minhwa-hero__text {
  grid-area: text;
  display: flex;
  flex-direction: column;
  gap: clamp(14px, 2.2vh, 22px);
  align-self: center;
}
.minhwa-hero__kicker {
  font-family: var(--font-kr);
  font-weight: 500;
  font-size: clamp(0.95rem, 1.4vw, 1.1rem);
  color: var(--minhwa-accent-deep);
  margin: 0;
  letter-spacing: 0.02em;
}
.minhwa-hero__kicker-en {
  display: inline;
  color: var(--ink-soft);
  font-size: 0.88em;
}
.minhwa-hero__title {
  font-family: var(--font-display);
  font-weight: 700;
  margin: 0;
  line-height: 0.95;
  color: var(--heuk);
}
.minhwa-hero__title-kr {
  display: block;
  font-size: clamp(4.6rem, 19vw, 13rem);
  letter-spacing: -0.01em;
}
.minhwa-hero__title-en {
  display: block;
  font-family: var(--font-en);
  font-style: italic;
  font-weight: 600;
  font-size: clamp(1.3rem, 3.4vw, 2.4rem);
  color: var(--ink-soft);
  margin-top: 0.1em;
  letter-spacing: 0.06em;
}
/* per-glyph reveal — KR lands with a stamp pop, EN settles */
.minhwa-hero__glyph {
  display: inline-block;
  opacity: 1;
}
.minhwa-js .minhwa-hero__glyph {
  opacity: 0;
  transform: translateY(0.12em);
  transition: opacity 700ms var(--ease-settle), transform 700ms var(--ease-settle);
  transition-delay: var(--pn, 0ms);
}
.minhwa-js .minhwa-hero__glyph--stamp {
  transition-timing-function: var(--ease-stamp);
  transform: translateY(0.18em) scale(0.86);
}
/* the hero title reveals on mount (no scroll needed — it's the first paint) */
.minhwa-js .minhwa-hero .minhwa-hero__glyph {
  animation: minhwa-glyph-in 760ms var(--ease-stamp) forwards;
  animation-delay: var(--pn, 0ms);
}
@keyframes minhwa-glyph-in {
  to {
    opacity: 1;
    transform: none;
  }
}

.minhwa-hero__lede {
  font-family: var(--font-kr);
  font-weight: 500;
  font-size: clamp(1.15rem, 2.4vw, 1.55rem);
  line-height: 1.6;
  color: var(--heuk);
  margin: 0;
  max-width: 30ch;
}
.minhwa-hero__lede-en {
  font-family: var(--font-en);
  font-style: italic;
  font-size: clamp(0.95rem, 1.6vw, 1.1rem);
  color: var(--ink-soft);
  margin: 0;
  max-width: 34ch;
  line-height: 1.6;
}

/* hero corner seal — decorative first mark */
.minhwa-hero__seal {
  position: absolute;
  top: clamp(20px, 4vw, 40px);
  right: clamp(20px, 5vw, 56px);
  width: clamp(58px, 7vw, 88px);
  height: clamp(58px, 7vw, 88px);
  transform-origin: center;
  z-index: 3;
}

.minhwa-hero__hint {
  grid-area: text;
  align-self: end;
  font-family: var(--font-kr);
  font-size: 0.9rem;
  color: var(--ink-soft);
  margin: clamp(16px, 3vh, 28px) 0 0;
  letter-spacing: 0.02em;
}
.minhwa-hero__hint span {
  font-family: var(--font-en);
  font-style: italic;
}

/* ============================ seal mark ============================ */

.minhwa-sealmark {
  display: block;
  width: 100%;
  height: 100%;
  filter: drop-shadow(0 4px 8px rgba(122, 36, 28, 0.22));
}

/* ============================ PEONY (section 02) ============================ */

.minhwa-peony {
  background: linear-gradient(180deg, var(--hanji) 0%, var(--hanji-deep) 100%);
}
.minhwa-peony__intro,
.minhwa-peony__intro-en {
  max-width: 880px;
  margin: 0 auto 0.6em;
  font-size: clamp(1rem, 1.6vw, 1.2rem);
}
.minhwa-peony__intro-en {
  color: var(--ink-soft);
  font-size: clamp(0.92rem, 1.4vw, 1.05rem);
}
.minhwa-peony__stage {
  max-width: 1120px;
  margin: clamp(32px, 5vh, 52px) auto 0;
  display: grid;
  grid-template-columns: minmax(0, 1.05fr) minmax(0, 1fr);
  gap: clamp(28px, 4vw, 56px);
  align-items: center;
}
.minhwa-peony__mount {
  position: relative;
  background: var(--hanji);
  border: 1px solid rgba(26, 20, 16, 0.16);
  padding: clamp(8px, 1.2vw, 14px);
  box-shadow: 0 18px 40px rgba(26, 20, 16, 0.14);
}
.minhwa-peony__art {
  display: block;
  width: 100%;
  height: auto;
  aspect-ratio: 1 / 1;
}
/* the seal that presses onto the peony — invisible until stamped */
.minhwa-peony__seal {
  position: absolute;
  right: clamp(10px, 2vw, 22px);
  bottom: clamp(10px, 2vw, 22px);
  width: clamp(64px, 9vw, 104px);
  height: clamp(64px, 9vw, 104px);
  pointer-events: none;
}
.minhwa-peony__seal.is-ready {
  opacity: 0;
  transform: translateY(-90%) scale(1.25);
}
.minhwa-peony__seal.is-ready .minhwa-sealmark {
  opacity: 0.45;
}
.minhwa-js .minhwa-peony__seal.is-stamped {
  opacity: 1;
  transform: none;
  animation: minhwa-seal-press 480ms var(--ease-press) forwards;
}
@keyframes minhwa-seal-press {
  0% {
    opacity: 0;
    transform: translateY(-90%) scale(1.25);
  }
  62% {
    opacity: 1;
    transform: translateY(4%) scale(0.97);
  }
  100% {
    opacity: 1;
    transform: none;
  }
}
/* the certifying ink rim — expands once the seal has landed */
.minhwa-peony__seal.is-stamped::after {
  content: "";
  position: absolute;
  inset: -6px;
  border-radius: 10px;
  border: 1px solid var(--seal-red);
  opacity: 0;
  animation: minhwa-seal-rim 360ms var(--ease-settle) 380ms forwards;
}
@keyframes minhwa-seal-rim {
  0% {
    opacity: 0.5;
    transform: scale(0.9);
  }
  100% {
    opacity: 0;
    transform: scale(1.12);
  }
}

.minhwa-peony__legend {
  display: flex;
  flex-direction: column;
  gap: clamp(16px, 2.4vh, 24px);
}
.minhwa-peony__meaning {
  font-family: var(--font-display);
  font-weight: 700;
  font-size: clamp(1.5rem, 3.6vw, 2.4rem);
  line-height: 1.28;
  color: var(--heuk);
  margin: 0;
}
.minhwa-peony__meaning-en {
  font-family: var(--font-en);
  font-style: italic;
  font-size: clamp(1rem, 1.8vw, 1.2rem);
  color: var(--ink-soft);
  margin: 0;
}
.minhwa-peony__dl {
  display: grid;
  grid-template-columns: auto 1fr;
  gap: 8px 18px;
  margin: 0;
  padding: clamp(14px, 2vw, 20px) 0 0;
  border-top: 1px solid rgba(26, 20, 16, 0.16);
}
.minhwa-peony__dl div {
  display: contents;
}
.minhwa-peony__dl dt {
  font-family: var(--font-display);
  font-weight: 700;
  color: var(--minhwa-accent-deep);
  font-size: 1.02em;
}
.minhwa-peony__dl dd {
  margin: 0;
  color: var(--heuk);
  font-size: 0.98em;
}

/* the press-the-seal button — folk weight, vermillion, never garish */
.minhwa-peony__press {
  appearance: none;
  -webkit-appearance: none;
  cursor: pointer;
  font-family: var(--font-display);
  font-weight: 700;
  text-align: left;
  display: inline-flex;
  flex-direction: column;
  gap: 4px;
  padding: clamp(12px, 2vw, 16px) clamp(18px, 2.4vw, 24px);
  background: var(--seal-red);
  color: var(--baek);
  border: none;
  border-radius: 4px;
  box-shadow: 4px 5px 0 var(--jeongjo);
  align-self: flex-start;
  transition: transform 180ms var(--ease-stamp), box-shadow 180ms var(--ease-settle),
    background 180ms var(--ease-settle);
}
.minhwa-peony__press-kr {
  font-size: clamp(1.05rem, 2vw, 1.3rem);
  letter-spacing: 0.01em;
}
.minhwa-peony__press-en {
  font-family: var(--font-en);
  font-style: italic;
  font-weight: 500;
  font-size: 0.78em;
  opacity: 0.92;
}
.minhwa-peony__press:hover {
  transform: translate(-1px, -1px);
  box-shadow: 5px 6px 0 var(--jeongjo);
}
.minhwa-peony__press:active {
  transform: translate(2px, 3px);
  box-shadow: 1px 2px 0 var(--jeongjo);
}
.minhwa-peony__press[data-stamped] {
  background: var(--hanji-deep);
  color: var(--minhwa-accent-deep);
  box-shadow: 2px 3px 0 rgba(26, 20, 16, 0.2);
  cursor: default;
}
.minhwa-peony__press:disabled {
  cursor: default;
}

/* ============================ OBANGSAEK (section 03) ============================ */

.minhwa-obang {
  background: var(--hanji);
}
.minhwa-obang__intro,
.minhwa-obang__intro-en {
  max-width: 880px;
  margin: 0 auto 0.6em;
  font-size: clamp(1rem, 1.6vw, 1.2rem);
}
.minhwa-obang__intro-en {
  color: var(--ink-soft);
  font-size: clamp(0.92rem, 1.4vw, 1.05rem);
}

/* the five-color rail — selectable swatches */
.minhwa-obang__rail {
  list-style: none;
  margin: clamp(32px, 5vh, 52px) auto 0;
  padding: 0;
  max-width: 1120px;
  display: grid;
  grid-template-columns: repeat(5, 1fr);
  gap: clamp(8px, 1.4vw, 16px);
}
.minhwa-obang__cell {
  min-width: 0;
}
.minhwa-obang__btn {
  appearance: none;
  -webkit-appearance: none;
  cursor: pointer;
  width: 100%;
  display: flex;
  flex-direction: column;
  gap: 8px;
  align-items: flex-start;
  padding: clamp(12px, 1.6vw, 16px);
  background: var(--hanji-deep);
  border: 1px solid rgba(26, 20, 16, 0.18);
  border-radius: 3px;
  font-family: inherit;
  color: var(--heuk);
  text-align: left;
  transition: transform 220ms var(--ease-stamp), border-color 220ms var(--ease-settle),
    box-shadow 220ms var(--ease-settle);
}
.minhwa-obang__btn:hover {
  transform: translateY(-3px);
}
.minhwa-obang__btn[data-active] {
  border-color: var(--minhwa-swatch-deep, var(--heuk));
  box-shadow: 0 0 0 2px var(--minhwa-swatch-deep, var(--heuk)),
    0 8px 18px rgba(26, 20, 16, 0.12);
}
/* baek swatch would vanish on hanji-deep; ring it with ink instead */
.minhwa-obang__btn[data-baek] .minhwa-obang__swatch {
  box-shadow: inset 0 0 0 1px rgba(26, 20, 16, 0.3);
}
.minhwa-obang__swatch {
  display: block;
  width: 100%;
  height: clamp(40px, 6vw, 64px);
  background: var(--minhwa-swatch);
  border-radius: 2px;
}
.minhwa-obang__hanja {
  font-family: var(--font-display);
  font-weight: 700;
  font-size: clamp(1.4rem, 3vw, 2rem);
  color: var(--heuk);
  line-height: 1;
}
.minhwa-obang__name {
  font-family: var(--font-display);
  font-weight: 700;
  font-size: 1.05rem;
  color: var(--heuk);
}
.minhwa-obang__name-en {
  font-family: var(--font-en);
  font-style: italic;
  font-weight: 500;
  font-size: 0.78em;
  color: var(--ink-soft);
}
.minhwa-obang__dir {
  font-family: var(--font-kr);
  font-size: 0.82rem;
  color: var(--ink-soft);
}
.minhwa-obang__dir span {
  font-family: var(--font-en);
  font-style: italic;
}

/* the notes — only the active one shows (no-JS: all visible) */
.minhwa-obang__notes {
  max-width: 880px;
  margin: clamp(28px, 4vh, 40px) auto 0;
  position: relative;
  min-height: 220px;
}
.minhwa-obang__note {
  background: var(--hanji-deep);
  border-left: 4px solid var(--jeok);
  padding: clamp(18px, 2.6vw, 26px);
  border-radius: 0 3px 3px 0;
}
/* with JS: stack them, show only the open one */
.minhwa-js .minhwa-obang__note {
  position: absolute;
  inset: 0;
  opacity: 0;
  transform: translateY(8px);
  transition: opacity 360ms var(--ease-settle), transform 360ms var(--ease-settle);
  pointer-events: none;
}
.minhwa-js .minhwa-obang__note.is-open {
  opacity: 1;
  transform: none;
  pointer-events: auto;
  position: relative;
}
.minhwa-obang__note-head {
  font-family: var(--font-display);
  font-weight: 700;
  font-size: clamp(1.2rem, 2.6vw, 1.7rem);
  margin: 0 0 0.4em;
  color: var(--heuk);
}
.minhwa-obang__note-en {
  font-family: var(--font-en);
  font-style: italic;
  font-weight: 500;
  font-size: 0.62em;
  color: var(--ink-soft);
}
.minhwa-obang__note-motif {
  font-family: var(--font-kr);
  font-weight: 500;
  color: var(--minhwa-accent-deep);
  margin: 0 0 0.5em;
  font-size: 1.02em;
}
.minhwa-obang__note-meaning {
  margin: 0 0 0.6em;
  color: var(--heuk);
}
.minhwa-obang__note-en {
  font-family: var(--font-en);
  font-style: italic;
  color: var(--ink-soft);
  margin: 0;
}

/* ============================ LONGEVITY (section 04, pinned scrub) ============================ */

/* The outer track is tall; the inner stage is sticky. Progress through the
   track drives --minhwa-longevity on the stage (set by useLongevityScrub). */
.minhwa-long {
  background: linear-gradient(180deg, var(--hanji-deep) 0%, var(--hanji) 100%);
  padding-bottom: 0;
}
.minhwa-long__head {
  padding-top: clamp(72px, 12vh, 140px);
}
.minhwa-long__stage {
  position: sticky;
  top: 0;
  height: 100svh;
  min-height: 560px;
  display: grid;
  grid-template-rows: 1fr auto;
  overflow: hidden;
}
/* the track gives the section scrollable height: 1vh of stage per ~0.1
   progress across ten symbols => ~ stage-height * (10 * 0.9). We express
   the tall track via padding-bottom on the section, leaving the sticky
   stage pinned. */
.minhwa-long {
  /* 800svh of scroll for the ten-step walk, plus the head. */
  padding-bottom: calc(800svh + clamp(72px, 12vh, 140px));
}

.minhwa-long__backdrop {
  position: absolute;
  inset: 0;
  z-index: 0;
}
.minhwa-long__art {
  display: block;
  width: 100%;
  height: 100%;
}
.minhwa-long__art .minhwa-picture__img {
  object-fit: cover;
  opacity: 0.5;
  filter: saturate(0.85);
}
.minhwa-long__scrim {
  position: absolute;
  inset: 0;
  background: linear-gradient(
    180deg,
    rgba(245, 239, 225, 0.62) 0%,
    rgba(245, 239, 225, 0.78) 55%,
    rgba(236, 227, 207, 0.92) 100%
  );
}

/* the orbiting ten symbols — a horizontal strip; the active one is lit.
   Active index = round(--minhwa-longevity * 9). We light a symbol when its
   index equals that active index, using a per-symbol --i custom prop. */
.minhwa-long__orbit {
  position: relative;
  z-index: 2;
  align-self: center;
  justify-self: center;
  list-style: none;
  margin: 0;
  padding: 0 clamp(16px, 4vw, 48px);
  display: flex;
  flex-wrap: wrap;
  justify-content: center;
  gap: clamp(8px, 1.6vw, 18px);
  max-width: 1120px;
  width: 100%;
}
.minhwa-long__sym {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 6px;
  padding: clamp(10px, 1.6vw, 16px) clamp(12px, 1.8vw, 20px);
  border-radius: 4px;
  background: rgba(251, 248, 239, 0.7);
  border: 1px solid rgba(26, 20, 16, 0.14);
  /* default dim; the active calc lights it up */
  opacity: 0.42;
  transform: scale(0.92);
  transition: opacity 420ms var(--ease-settle), transform 420ms var(--ease-stamp),
    background 420ms var(--ease-settle);
}
/* the active symbol — derived purely from --minhwa-longevity via round() */
.minhwa-js .minhwa-long__stage .minhwa-long__sym {
  opacity: calc(
    0.42 + 0.58 * clamp(0, 1, 1 - abs(var(--i) - round(var(--minhwa-longevity) * 9)))
  );
  transform: scale(
    calc(0.92 + 0.16 * clamp(0, 1, 1 - abs(var(--i) - round(var(--minhwa-longevity) * 9))))
  );
  background: calc(
    var(--baek) * clamp(0, 1, 1 - abs(var(--i) - round(var(--minhwa-longevity) * 9)))
    + rgba(251, 248, 239, 0.7) * (1 - clamp(0, 1, 1 - abs(var(--i) - round(var(--minhwa-longevity) * 9))))
  );
}
/* fallback: browsers without round() (older engines) — symbols stay at the
   dim default; the wishes remain readable because the no-JS block below
   reveals all of them. round() shipped in every current browser by 2024. */
.minhwa-long__sym-glyph {
  font-family: var(--font-display);
  font-weight: 700;
  font-size: clamp(1.4rem, 3.4vw, 2.4rem);
  color: var(--heuk);
  line-height: 1;
}
.minhwa-long__sym-en {
  font-family: var(--font-en);
  font-style: italic;
  font-size: 0.7rem;
  color: var(--ink-soft);
  letter-spacing: 0.02em;
}

/* the crossfading wishes — same active calc */
.minhwa-long__wishes {
  position: relative;
  z-index: 2;
  align-self: end;
  justify-self: center;
  width: 100%;
  max-width: 760px;
  padding: 0 clamp(20px, 5vw, 48px) clamp(24px, 5vh, 48px);
  text-align: center;
  min-height: 88px;
}
.minhwa-long__wish {
  margin: 0;
  display: flex;
  flex-direction: column;
  gap: 4px;
}
.minhwa-js .minhwa-long__wish {
  position: absolute;
  inset: 0;
  padding: 0 clamp(20px, 5vw, 48px);
  opacity: calc(
    clamp(0, 1, 1 - abs(var(--i) - round(var(--minhwa-longevity) * 9))) * 0.9 + 0.1
  );
  transform: translateY(
    calc(8px - 8px * clamp(0, 1, 1 - abs(var(--i) - round(var(--minhwa-longevity) * 9))))
  );
  transition: opacity 420ms var(--ease-settle), transform 420ms var(--ease-settle);
}
.minhwa-long__wish-kr {
  font-family: var(--font-display);
  font-weight: 700;
  font-size: clamp(1.15rem, 2.6vw, 1.7rem);
  color: var(--heuk);
}
.minhwa-long__wish-en {
  font-family: var(--font-en);
  font-style: italic;
  font-size: clamp(0.9rem, 1.4vw, 1.05rem);
  color: var(--ink-soft);
}

/* progress rail */
.minhwa-long__rail {
  position: relative;
  z-index: 2;
  align-self: end;
  justify-self: center;
  width: min(760px, 86vw);
  margin: 0 auto clamp(20px, 4vh, 36px);
}
.minhwa-long__rail-fill {
  display: block;
  height: 3px;
  width: calc(var(--minhwa-longevity, 0) * 100%);
  background: var(--jeok);
  border-radius: 2px;
  transition: width 120ms linear;
}
.minhwa-long__rail::before {
  content: "";
  position: absolute;
  inset: 0;
  height: 3px;
  top: auto;
  background: rgba(26, 20, 16, 0.14);
  border-radius: 2px;
}
.minhwa-long__rail-label {
  display: block;
  margin-top: 8px;
  font-family: var(--font-kr);
  font-size: 0.82rem;
  color: var(--ink-soft);
  text-align: center;
}
.minhwa-long__rail-label span {
  font-family: var(--font-en);
  font-style: italic;
}

/* ============================ FOOTER (section 05) ============================ */

.minhwa-foot {
  background: var(--hanji-deep);
  border-top: 1px solid rgba(26, 20, 16, 0.16);
}
.minhwa-foot__grid {
  max-width: 1120px;
  margin: 0 auto;
  display: grid;
  grid-template-columns: repeat(3, minmax(0, 1fr));
  gap: clamp(28px, 4vw, 56px);
}
.minhwa-foot__col-h {
  font-family: var(--font-display);
  font-weight: 700;
  font-size: 1.25rem;
  color: var(--minhwa-accent-deep);
  margin: 0 0 0.6em;
  border-bottom: 1px solid rgba(26, 20, 16, 0.16);
  padding-bottom: 0.3em;
}
.minhwa-foot__col-body {
  margin: 0 0 0.8em;
  color: var(--heuk);
  font-size: 0.96em;
}
.minhwa-foot__col-en {
  color: var(--ink-soft);
  font-size: 0.9em;
}
.minhwa-foot__obang {
  list-style: none;
  margin: 0;
  padding: 0;
  display: flex;
  flex-direction: column;
  gap: 10px;
}
.minhwa-foot__obang li {
  display: flex;
  align-items: center;
  gap: 12px;
  font-family: var(--font-kr);
  font-size: 0.95em;
  color: var(--heuk);
}
.minhwa-foot__dot {
  display: inline-block;
  width: 18px;
  height: 18px;
  border-radius: 2px;
  flex-shrink: 0;
}
.minhwa-foot__dot--cheong {
  background: var(--cheong);
}
.minhwa-foot__dot--jeok {
  background: var(--jeok);
}
.minhwa-foot__dot--hwang {
  background: var(--hwang);
}
.minhwa-foot__dot--baek {
  background: var(--baek);
  box-shadow: inset 0 0 0 1px rgba(26, 20, 16, 0.3);
}
.minhwa-foot__dot--heuk {
  background: var(--heuk);
}
.minhwa-foot__ledger,
.minhwa-foot__addr,
.minhwa-foot__hours {
  margin: 0 0 0.6em;
  font-family: var(--font-kr);
  font-size: 0.96em;
  color: var(--heuk);
  font-variant-numeric: lining-nums tabular-nums;
}
.minhwa-foot__ledger-en,
.minhwa-foot__addr-en,
.minhwa-foot__hours-en {
  display: block;
  font-family: var(--font-en);
  font-style: italic;
  color: var(--ink-soft);
  font-size: 0.9em;
}

.minhwa-foot__sign {
  max-width: 1120px;
  margin: clamp(48px, 8vh, 80px) auto 0;
  padding-top: clamp(28px, 4vh, 40px);
  border-top: 1px solid rgba(26, 20, 16, 0.16);
  display: grid;
  grid-template-columns: auto 1fr;
  grid-template-areas:
    "seal signoff"
    "seal copy"
    "top top";
  gap: 8px clamp(20px, 3vw, 32px);
  align-items: center;
}
.minhwa-foot__seal {
  grid-area: seal;
  width: clamp(56px, 7vw, 84px);
  height: clamp(56px, 7vw, 84px);
}
.minhwa-foot__signoff {
  grid-area: signoff;
  margin: 0;
  font-family: var(--font-display);
  font-weight: 700;
  font-size: clamp(1.1rem, 2.4vw, 1.5rem);
  color: var(--heuk);
}
.minhwa-foot__signoff-en {
  font-family: var(--font-en);
  font-style: italic;
  font-size: 0.7em;
  color: var(--ink-soft);
}
.minhwa-foot__copy {
  grid-area: copy;
  margin: 0;
  font-size: 0.82rem;
  color: var(--ink-soft);
}
.minhwa-foot__copy span {
  font-family: var(--font-en);
  font-style: italic;
}
.minhwa-foot__top {
  grid-area: top;
  justify-self: start;
  margin-top: 8px;
  font-family: var(--font-display);
  font-weight: 700;
  color: var(--minhwa-accent-deep);
  text-decoration: none;
  border-bottom: 2px solid var(--minhwa-accent-live);
  padding: 2px 0;
  transition: color 180ms var(--ease-settle);
}
.minhwa-foot__top span:last-child {
  font-family: var(--font-en);
  font-style: italic;
  font-weight: 500;
}
.minhwa-foot__top:hover {
  color: var(--minhwa-accent-live);
}

/* ============================ narration (split text) ============================ */

.minhwa-narration {
  display: inline;
}
.minhwa-narration__row {
  display: inline;
}
.minhwa-narration__g {
  display: inline-block;
  opacity: 1;
}
.minhwa-js .minhwa-narration__g {
  opacity: 0;
  transform: translateY(0.12em);
  transition: opacity 600ms var(--ease-settle), transform 600ms var(--ease-settle);
  transition-delay: var(--pn, 0ms);
}
/* the narration animates in once its panel is visible */
.minhwa-js [data-reveal="panel"].is-visible .minhwa-narration__g {
  opacity: 1;
  transform: none;
}
/* hero narration fires on the hero panel (visible from first paint — the
   reveal observer marks the in-view hero header is-visible on mount) */

/* ============================ responsive ============================ */

@media (max-width: 900px) {
  .minhwa-hero {
    grid-template-columns: 1fr;
    grid-template-areas:
      "mount"
      "text";
    text-align: left;
  }
  .minhwa-hero__art {
    height: clamp(360px, 60vh, 520px);
  }
  .minhwa-peony__stage {
    grid-template-columns: 1fr;
  }
  .minhwa-obang__rail {
    grid-template-columns: repeat(2, 1fr);
  }
  .minhwa-foot__grid {
    grid-template-columns: 1fr;
  }
  .minhwa-foot__sign {
    grid-template-columns: auto 1fr;
    grid-template-areas:
      "seal signoff"
      "seal copy"
      "top top";
  }
}

@media (max-width: 560px) {
  .minhwa-obang__rail {
    grid-template-columns: 1fr;
  }
  .minhwa-long__orbit {
    gap: 6px;
  }
  .minhwa-long__sym {
    padding: 8px 10px;
  }
}

/* ============================ reduced motion ============================ */
/* A complete, composed, static page — not a paused animation. Every
   pre-reveal state forced to final; ambient cycles dead; stamps land
   instantly; the longevity section opens as a composed grid. */

@media (prefers-reduced-motion: reduce) {
  .minhwa-root,
  .minhwa-root * {
    animation-duration: 0.001ms !important;
    animation-delay: 0ms !important;
    animation-iteration-count: 1 !important;
    transition-duration: 0.001ms !important;
    transition-delay: 0ms !important;
    scroll-behavior: auto !important;
  }
  /* all pre-reveal states → final */
  .minhwa-js [data-reveal]:not(.is-visible),
  .minhwa-js [data-reveal="stamp"]:not(.is-visible) {
    opacity: 1 !important;
    transform: none !important;
  }
  /* glyph + narration lines whole */
  .minhwa-js .minhwa-hero__glyph,
  .minhwa-js .minhwa-narration__g {
    opacity: 1 !important;
    transform: none !important;
  }
  /* ambient hero accents still visible, just still */
  .minhwa-hero__sun,
  .minhwa-hero__moon {
    animation: none !important;
  }
  /* seal already stamped (useSealStamp forces it under reduced motion) —
     land it instantly with no press animation */
  .minhwa-peony__seal.is-stamped {
    animation: none !important;
    opacity: 1 !important;
    transform: none !important;
  }
  .minhwa-peony__seal.is-stamped::after {
    animation: none !important;
    opacity: 0 !important;
  }
  /* longevity section: disable the pin, open as a composed grid. The
     [data-minhwa-reduced] flag is set on the section by page.tsx. */
  .minhwa-long[data-minhwa-reduced] {
    padding-bottom: clamp(72px, 12vh, 140px);
  }
  .minhwa-long[data-minhwa-reduced] .minhwa-long__stage {
    position: static;
    height: auto;
    min-height: 0;
    grid-template-rows: auto auto auto;
  }
  .minhwa-long[data-minhwa-reduced] .minhwa-long__backdrop {
    position: relative;
    height: clamp(220px, 40vh, 360px);
  }
  .minhwa-long[data-minhwa-reduced] .minhwa-long__sym {
    opacity: 1 !important;
    transform: none !important;
    background: rgba(251, 248, 239, 0.85) !important;
  }
  .minhwa-long[data-minhwa-reduced] .minhwa-long__wish {
    position: relative !important;
    opacity: 1 !important;
    transform: none !important;
    padding: 4px 0;
  }
  .minhwa-long[data-minhwa-reduced] .minhwa-long__wishes {
    min-height: 0;
    text-align: center;
  }
  .minhwa-long[data-minhwa-reduced] .minhwa-long__rail-fill {
    width: 100%;
  }
}

/* ============================ no-JS fallback ============================ */
/* Without .minhwa-js, every pre-reveal style is bypassed and the whole
   gallery reads as finished: every minhwa, every meaning, every seal
   visible. The longevity section opens as a composed grid (no pin). */
.minhwa-root:not(.minhwa-js) .minhwa-long__stage {
  position: static;
  height: auto;
  min-height: 0;
  grid-template-rows: auto auto auto;
}
.minhwa-root:not(.minhwa-js) .minhwa-long {
  padding-bottom: clamp(72px, 12vh, 140px);
}
.minhwa-root:not(.minhwa-js) .minhwa-long__backdrop {
  position: relative;
  height: clamp(220px, 40vh, 360px);
}
.minhwa-root:not(.minhwa-js) .minhwa-long__sym,
.minhwa-root:not(.minhwa-js) .minhwa-long__wish {
  opacity: 1 !important;
  transform: none !important;
  position: relative !important;
}
.minhwa-root:not(.minhwa-js) .minhwa-obang__note {
  position: relative !important;
  opacity: 1 !important;
  transform: none !important;
  pointer-events: auto;
  margin-bottom: 12px;
}
